"""
IoT Sensor Data Collection Module
Simulates reading from various sensors and creating data payloads
for transmission to IoT gateways or cloud platforms.
"""
import json
import random
import time
from datetime import datetime
from typing import Dict, List, Any

class Sensor:
 """Base class for IoT sensors"""
 def __init__(self, name: str, unit: str, min_val: float, max_val: float):
 self.name = name
 self.unit = unit
 self.min_val = min_val
 self.max_val = max_val

 def read(self) -> float:
 """Simulate sensor reading with random value"""
 return random.uniform(self.min_val, self.max_val)

 def calibrate(self, raw_value: float) -> float:
 """Apply calibration - can be overridden for specific sensors"""
 return round(raw_value, 2)

class TemperatureSensor(Sensor):
 """Temperature sensor with specific calibration"""
 def __init__(self):
 super().__init__("temperature", "°C", -10.0, 50.0)

 def calibrate(self, raw_value: float) -> float:
 // Apply offset calibration
 calibrated = raw_value - 0.5
 return round(calibrated, 2)

class HumiditySensor(Sensor):
 """Humidity sensor"""
 def __init__(self):
 super().__init__("humidity", "%", 0.0, 100.0)

class MotionSensor(Sensor):
 """Motion detection sensor"""
 def __init__(self):
 super().__init__("motion", "boolean", 0.0, 1.0)

 def read(self) -> bool:
 return random.choice([True, False])

class IoTDevice:
 """Represents an IoT physical device with multiple sensors"""
 def __init__(self, device_id: str):
 self.device_id = device_id
 self.sensors: List[Sensor] = []
 self.is_connected = False

 def add_sensor(self, sensor: Sensor):
 self.sensors.append(sensor)

 def collect_data(self) -> Dict[str, Any]:
 """Collect data from all connected sensors"""
 sensor_readings = {}

 for sensor in self.sensors:
 raw_value = sensor.read()
 calibrated_value = sensor.calibrate(raw_value)

 if isinstance(sensor, MotionSensor):
 sensor_readings[sensor.name] = "detected" if calibrated_value else "none"
 else:
 sensor_readings[sensor.name] = {
 "value": calibrated_value,
 "unit": sensor.unit
 }

 return sensor_readings

 def create_payload(self) -> str:
 """Create JSON payload for transmission"""
 data = {
 "device_id": self.device_id,
 "timestamp": datetime.now().isoformat(),
 "sensors": self.collect_data(),
 "status": "active"
 }
 return json.dumps(data, indent=2)

 def simulate_operation(self, iterations: int = 3):
 """Simulate device operation cycle"""
 print(f"=== IoT Device {self.device_id} Simulation ===\n")

 for i in range(iterations):
 print(f"--- Reading Cycle {i+1} ---")
 payload = self.create_payload()
 print(payload)
 print()
 time.sleep(1)

# Demo usage
if __name__ == "__main__":
 # Create IoT device with sensors
 device = IoTDevice("SENSOR_NODE_001")
 device.add_sensor(TemperatureSensor())
 device.add_sensor(HumiditySensor())
 device.add_sensor(MotionSensor())

 # Run simulation
 device.simulate_operation(2)

/*
 * IoT Temperature Monitor with Fan Control
 * Demonstrates: Sensor reading, Actuator control, Threshold-based decisions
 * Hardware: Temperature sensor (LM35), LED, Fan (via relay)
 */

#include <stdio.h>

// Pin definitions
#define TEMP_SENSOR_PIN A0
#define LED_PIN 13
#define FAN_PIN 12
#define BUZZER_PIN 11

// Threshold values
#define TEMP_HIGH_THRESHOLD 30.0 // Celsius
#define TEMP_LOW_THRESHOLD 18.0 // Celsius
#define TEMP_CRITICAL 40.0 // Celsius

// Device configuration
#define SAMPLE_COUNT 5
#define READ_DELAY_MS 100

// Global variables
float temperature = 0.0;
int motionDetected = 0;

/*
 * Initialize all hardware components
 */
void initializeHardware() {
 // Set pin modes
 pinMode(LED_PIN, OUTPUT);
 pinMode(FAN_PIN, OUTPUT);
 pinMode(BUZZER_PIN, OUTPUT);
 pinMode(TEMP_SENSOR_PIN, INPUT);

 // Initialize serial communication
 Serial.begin(9600);

 // Turn off all outputs initially
 digitalWrite(LED_PIN, LOW);
 digitalWrite(FAN_PIN, LOW);
 digitalWrite(BUZZER_PIN, LOW);

 Serial.println("IoT Device Initialized");
}

/*
 * Read temperature from LM35 sensor
 * LM35: 10mV per degree Celsius
 * ADC: 10-bit (0-1023) for 5V reference
 */
float readTemperature() {
 int adcValue = 0;
 float voltage = 0.0;
 float tempCelsius = 0.0;

 // Take multiple samples for accuracy
 for (int i = 0; i < SAMPLE_COUNT; i++) {
 adcValue += analogRead(TEMP_SENSOR_PIN);
 delay(READ_DELAY_MS);
 }
 adcValue = adcValue / SAMPLE_COUNT;

 // Convert ADC value to voltage
 voltage = (adcValue * 5.0) / 1023.0;

 // Convert voltage to temperature (LM35: 10mV/°C)
 tempCelsius = voltage * 100.0;

 return tempCelsius;
}

/*
 * Control actuators based on temperature readings
 */
void controlActuators(float temp) {
 // Fan control based on temperature
 if (temp > TEMP_HIGH_THRESHOLD) {
 digitalWrite(FAN_PIN, HIGH);
 digitalWrite(LED_PIN, HIGH);
 Serial.println("Status: Cooling ACTIVE");
 } else if (temp < TEMP_LOW_THRESHOLD) {
 digitalWrite(FAN_PIN, LOW);
 digitalWrite(BUZZER_PIN, HIGH); // Alert for low temp
 Serial.println("Status: Temperature LOW - Alert!");
 } else {
 digitalWrite(FAN_PIN, LOW);
 digitalWrite(BUZZER_PIN, LOW);
 digitalWrite(LED_PIN, LOW);
 Serial.println("Status: Normal");
 }

 // Critical temperature alert
 if (temp >= TEMP_CRITICAL) {
 // Rapid buzzer for critical alert
 tone(BUZZER_PIN, 1000);
 Serial.println("ALERT: CRITICAL TEMPERATURE!");
 }
}

/*
 * Create and send data payload
 */
void transmitData(float temp, int fanState, int ledState) {
 // Simulate creating JSON payload
 Serial.println("--- Transmitting Data ---");
 Serial.print("{\n \"device_id\": \"ARDUINO_NODE_01\",\n");
 Serial.print(" \"temperature\": ");
 Serial.print(temp);
 Serial.print(",\n");
 Serial.print(" \"fan_status\": \"");
 Serial.print(fanState ? "ON" : "OFF");
 Serial.print("\",\n");
 Serial.print(" \"led_status\": \"");
 Serial.print(ledState ? "ON" : "OFF");
 Serial.print("\",\n");
 Serial.print(" \"timestamp\": \"2024-01-15T10:30:00Z\"\n");
 Serial.println("}");
}

/*
 * Enter low power mode to conserve energy
 */
void enterSleepMode(unsigned long durationMs) {
 // In real implementation: use sleep modes
 // For demo: simple delay
 Serial.print("Entering low power mode for ");
 Serial.print(durationMs / 1000);
 Serial.println(" seconds...");
 delay(durationMs);
}

/*
 * Main setup function
 */
void setup() {
 initializeHardware();
 delay(1000); // Wait for sensors to stabilize
}

/*
 * Main loop - runs continuously
 */
void loop() {
 // Step 1: Read sensor data
 temperature = readTemperature();

 // Step 2: Display readings
 Serial.print("Temperature: ");
 Serial.print(temperature);
 Serial.println(" °C");

 // Step 3: Control actuators based on thresholds
 controlActuators(temperature);

 // Step 4: Transmit data to gateway
 transmitData(temperature, digitalRead(FAN_PIN), digitalRead(LED_PIN));

 // Step 5: Sleep for power efficiency (10 seconds)
 enterSleepMode(10000);
}
